  1→import React from 'react';
  2→import { useNavigate } from 'react-router-dom';
  3→import { useAuth } from '../../../Context/useAuth';
  4→import { useMyStories } from '../hooks/useStoryData';
  5→import { useDeleteStory } from '../hooks/useStoryMutations';
  6→import { motion, AnimatePresence } from 'framer-motion';
  7→import { BeatLoader } from 'react-spinners';
  8→import './StoryDashboard.css';
  9→
 10→const STATUS_LABELS = {
 11→    ongoing: 'Ongoing',
 12→    completed: 'Completed',
 13→    hiatus: 'Hiatus',
 14→};
 15→
 16→const StoryDashboard = () => {
 17→    const { session } = useAuth();
 18→    const token = session?.access_token;
 19→    const navigate = useNavigate();
 20→
 21→    const { data: stories, isLoading } = useMyStories(token);
 22→    const deleteMutation = useDeleteStory(token);
 23→
 24→    const handleDelete = (e, storyId, title) => {
 25→        e.stopPropagation();
 26→        if (window.confirm(`Delete "${title}"? This cannot be undone.`)) {
 27→            deleteMutation.mutate(storyId);
 28→        }
 29→    };
 30→
 31→    const getTotalWords = (chapters) => {
 32→        if (!chapters) return 0;
 33→        return chapters.reduce((sum, ch) => sum + (ch.word_count || 0), 0);
 34→    };
 35→
 36→    const getPublishedCount = (chapters) => {
 37→        if (!chapters) return 0;
 38→        return chapters.filter(ch => ch.status === 'published').length;
 39→    };
 40→
 41→    if (isLoading) {
 42→        return (
 43→            <div className="story-dashboard">
 44→                <div className="story-dashboard-loading">
 45→                    <BeatLoader size={10} color="var(--text-muted)" />
 46→                </div>
 47→            </div>
 48→        );
 49→    }
 50→
 51→    return (
 52→        <div className="story-dashboard">
 53→            <div className="story-dashboard-header">
 54→                <button className="story-dashboard-back" onClick={() => navigate(-1)}>
 55→                    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="var(--text-secondary)">
 56→                        <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
 57→                    </svg>
 58→                </button>
 59→                <h2 className="story-dashboard-title">My Stories</h2>
 60→                <button
 61→                    className="story-dashboard-new-btn"
 62→                    onClick={() => navigate('/home/stories/new')}
 63→                >
 64→                    + New Story
 65→                </button>
 66→            </div>
 67→
 68→            {(!stories || stories.length === 0) ? (
 69→                <div className="story-dashboard-empty">
 70→                    <p>You haven't written any stories yet.</p>
 71→                    <button
 72→                        className="story-dashboard-new-btn"
 73→                        onClick={() => navigate('/home/stories/new')}
 74→                    >
 75→                        Write Your First Story
 76→                    </button>
 77→                </div>
 78→            ) : (
 79→                <div className="story-dashboard-list">
 80→                    <AnimatePresence>
 81→                        {stories.map((story) => (
 82→                            <motion.div
 83→                                key={story.id}
 84→                                className="story-dashboard-card"
 85→                                initial={{ opacity: 0, y: 10 }}
 86→                                animate={{ opacity: 1, y: 0 }}
 87→                                exit={{ opacity: 0, y: -10 }}
 88→                                onClick={() => navigate(`/home/stories/${story.id}/manage`)}
 89→                            >
 90→                                <div className="story-dashboard-card-cover">
 91→                                    {story.cover_url ? (
 92→                                        <img src={story.cover_url} alt={story.title} loading="lazy" />
 93→                                    ) : (
