import { BeatLoader } from 'react-spinners';
import './StoryLibrary.css';

const STATUS_LABELS = {
    ongoing: 'Ongoing',
    completed: 'Completed',
    hiatus: 'Hiatus',
};

const StoryLibrary = () => {
    const { session } = useAuth();
    const token = session?.access_token;
    const navigate = useNavigate();

    const { data, fetchNextPage, hasNextPage, isFetchingNextPage, isLoading } = useMyLibrary(token);
    const stories = data?.pages?.flatMap(page => page.data) || [];
    const toggleLibrary = useToggleLibrary(token);

    const { ref: sentinelRef, inView } = useInView();
    useEffect(() => {
        if (inView && hasNextPage && !isFetchingNextPage) {
            fetchNextPage();
        }
    }, [inView, hasNextPage, isFetchingNextPage, fetchNextPage]);

    const handleRemove = (e, storyId) => {
        e.stopPropagation();
        toggleLibrary.mutate(storyId);
    };

    if (isLoading) {
        return (
            <div className="story-library">
                <div className="story-library-loading">
                    <BeatLoader size={10} color="var(--text-muted)" />
                </div>
            </div>
        );
    }

    return (
        <div className="story-library">
            <div className="story-library-header">
                <button className="story-library-back" onClick={() => navigate(-1)}>
                    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="var(--text-secondary)">
                        <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
                    </svg>
                </button>
                <h2 className="story-library-title">My Library</h2>
            </div>

            {(!isLoading && stories.length === 0) ? (
                <div className="story-library-empty">
                    <p>Your library is empty.</p>
                    <button
                        className="story-library-browse-btn"
                        onClick={() => navigate('/home/stories')}
                    >
                        Browse Stories
                    </button>
                </div>
            ) : (
                <div className="story-library-list">
                    <AnimatePresence>
                        {stories.map((story) => (
                            <motion.div
                                key={story.id}
                                className="story-library-card"
                                initial={{ opacity: 0, y: 10 }}
                                animate={{ opacity: 1, y: 0 }}
                                exit={{ opacity: 0, y: -10 }}
                                onClick={() => navigate(`/home/stories/${story.id}`)}
                            >
                                <div className="story-library-card-cover">
                                    {story.cover_url ? (
                                        <img src={story.cover_url} alt={story.title} loading="lazy" />
                                    ) : (
                                        <div className="story-library-card-cover-placeholder">
                                            <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="var(--text-muted)">
                                                <path d="M21 5c-1.11-.35-2.33-.5-3.5-.5-1.95 0-4.05.4-5.5 1.5-1.45-1.1-3.55-1.5-5.5-1.5S2.45 4.9 1 6v14.65c0 .25.25.5.5.5.1 0 .15-.05.25-.05C3.1 20.45 5.05 20 6.5 20c1.95 0 4.05.4 5.5 1.5 1.35-.85 3.8-1.5 5.5-1.5 1.65 0 3.35.3 4.75 1.05.1.05.15.05.25.05.25 0 .5-.25.5-.5V6c-.6-.45-1.25-.75-2-1zm0 13.5c-1.1-.35-2.3-.5-3.5-.5-1.7 0-4.15.65-5.5 1.5V8c1.35-.85 3.8-1.5 5.5-1.5 1.2 0 2.4.15 3.5.5v11.5z"/>
                                            </svg>
                                        </div>
                                    )}
                                </div>
                                <div className="story-library-card-info">
                                    <h3 className="story-library-card-title">{story.title}</h3>
                                    {story.users && (
                                        <div className="story-library-card-author">
                                            {story.users.image_url && (
                                                <img src={story.users.image_url} alt="" className="story-library-card-author-avatar" />
                                            )}
                                            <span>{story.users.name}</span>
                                        </div>
                                    )}
                                    <div className="story-library-card-meta">
                                        <span className={`story-status-badge story-status-${story.status}`}>
                                            {STATUS_LABELS[story.status] || story.status}
                                        </span>
                                    </div>
                                    <div className="story-library-card-stats">
                                        <span>{story.vote_count || 0} votes</span>
                                        <span>{story.read_count || 0} reads</span>
                                    </div>
                                </div>
                                <div className="story-library-card-actions">
                                    <button
                                        className="story-library-remove-btn"
                                        onClick={(e) => handleRemove(e, story.id)}
                                        title="Remove from library"
                                    >
                                        <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="currentColor">
                                            <path d="M17 3H7c-1.1 0-2 .9-2 2v16l7-3 7 3V5c0-1.1-.9-2-2-2z"/>
                                        </svg>
                                    </button>
                                </div>
                            </motion.div>
                        ))}
                    </AnimatePresence>
                </div>
            )}
        </div>
    );
};

export default StoryLibrary;

