  1→import { useState, useEffect, useCallback, useRef } from 'react';
  2→
  3→const HOVER_LEAVE_DELAY_MS = 450;
  4→
  5→const CommentBadge = ({ count, hasComments }) => {
  6→    return (
  7→        <>
  8→            {hasComments ? (
  9→                <svg width="13" height="13" viewBox="0 0 24 24" fill="currentColor" stroke="none">
 10→                    <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
 11→                </svg>
 12→            ) : (
 13→                <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
 14→                    <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
 15→                </svg>
 16→            )}
 17→            {hasComments && <span className="pcl-badge-count">{count}</span>}
 18→        </>
 19→    );
 20→};
 21→
 22→const ParagraphCommentLayer = ({ containerRef, commentCounts, onParagraphClick }) => {
 23→    const [paragraphs, setParagraphs] = useState([]);
 24→    const [hoveredIndex, setHoveredIndex] = useState(null);
 25→    const listenersRef = useRef([]);
 26→    const leaveTimerRef = useRef(null);
 27→    const layerRef = useRef(null);
 28→
 29→    const clearLeaveTimer = useCallback(() => {
 30→        if (leaveTimerRef.current) {
 31→            clearTimeout(leaveTimerRef.current);
 32→            leaveTimerRef.current = null;
 33→        }
 34→    }, []);
 35→
 36→    const scheduleLeave = useCallback((idx) => {
 37→        clearLeaveTimer();
 38→        leaveTimerRef.current = setTimeout(() => {
 39→            setHoveredIndex((prev) => prev === idx ? null : prev);
 40→        }, HOVER_LEAVE_DELAY_MS);
 41→    }, [clearLeaveTimer]);
 42→
 43→    const scanParagraphs = useCallback(() => {
 44→        const container = containerRef.current;
 45→        if (!container) return;
 46→
 47→        listenersRef.current.forEach(({ el, enter, leave, click }) => {
 48→            el.removeEventListener('mouseenter', enter);
 49→            el.removeEventListener('mouseleave', leave);
 50→            el.removeEventListener('click', click);
 51→        });
 52→        listenersRef.current = [];
 53→
 54→        const elements = container.querySelectorAll('.editor-paragraph');
 55→        const result = [];
 56→        let realIndex = 0;
 57→
 58→        elements.forEach((el) => {
 59→            const text = el.textContent.trim();
 60→            if (!text) return;
 61→
 62→            const idx = realIndex;
 63→            el.setAttribute('data-paragraph-index', idx);
 64→            const fingerprint = text.substring(0, 100);
 65→
 66→            result.push({
 67→                index: idx,
 68→                top: el.offsetTop,
 69→                height: el.offsetHeight,
 70→                text,
 71→                fingerprint,
 72→            });
 73→
 74→            const enter = () => {
 75→                clearLeaveTimer();
 76→                setHoveredIndex(idx);
 77→            };
 78→            const leave = (event) => {
 79→                const nextTarget = event.relatedTarget;
 80→                const layer = layerRef.current;
 81→
 82→                // Prevent hide jitter when moving directly from paragraph to badge.
 83→                if (nextTarget && layer && layer.contains(nextTarget)) {
 84→                    return;
 85→                }
 86→
 87→                scheduleLeave(idx);
 88→            };
 89→            const click = () => {
 90→                clearLeaveTimer();
 91→                setHoveredIndex(idx);
 92→            };
 93→            el.addEventListener('mouseenter', enter);
 94→            el.addEventListener('mouseleave', leave);
 95→            el.addEventListener('click', click);
 96→            listenersRef.current.push({ el, enter, leave, click });
 97→
 98→            realIndex++;
 99→        });
100→
101→        setParagraphs(result);
102→    }, [containerRef, clearLeaveTimer, scheduleLeave]);
103→
104→    useEffect(() => {
105→        const container = containerRef.current;
106→        if (!container) return;
107→
108→        const timer = setTimeout(scanParagraphs, 300);
109→
110→        const observer = new MutationObserver((mutations) => {
111→            // Ignore mutations from our own badge layer to prevent feedback loops
112→            const layer = layerRef.current;
113→            const isOwnMutation = layer && mutations.every(
114→                (m) => layer.contains(m.target)
115→            );
116→            if (isOwnMutation) return;
117→            scanParagraphs();
118→        });
119→
120→        observer.observe(container, { childList: true, subtree: true, characterData: true });
121→        window.addEventListener('resize', scanParagraphs);
122→
123→        return () => {
124→            clearTimeout(timer);
125→            clearLeaveTimer();
126→            observer.disconnect();
127→            window.removeEventListener('resize', scanParagraphs);
128→            listenersRef.current.forEach(({ el, enter, leave, click }) => {
129→                el.removeEventListener('mouseenter', enter);
130→                el.removeEventListener('mouseleave', leave);
131→                el.removeEventListener('click', click);
132→            });
133→            listenersRef.current = [];
134→        };
135→    }, [containerRef, scanParagraphs, clearLeaveTimer]);
136→
137→    const handleBadgeEnter = useCallback((idx) => {
138→        clearLeaveTimer();
139→        setHoveredIndex(idx);
140→    }, [clearLeaveTimer]);
141→
142→    const handleBadgeLeave = useCallback((idx, event) => {
143→        const nextTarget = event.relatedTarget;
144→        const nextParagraph = nextTarget?.closest?.('.editor-paragraph[data-paragraph-index]');
145→
146→        // Prevent hide jitter when moving directly from badge back to the paragraph.
147→        if (nextParagraph && Number(nextParagraph.getAttribute('data-paragraph-index')) === idx) {
148→            return;
149→        }
150→
151→        scheduleLeave(idx);
152→    }, [scheduleLeave]);
153→
154→    const counts = commentCounts || {};
155→
156→    return (
157→        <div className="pcl-layer" ref={layerRef}>
158→            {paragraphs.map((p) => {
159→                const count = counts[p.index] || 0;
160→                const hasComments = count > 0;
161→                const isVisible = hoveredIndex === p.index || hasComments;
162→
163→                return (
164→                    <div
165→                        key={p.index}
166→                        className={`pcl-badge-anchor ${isVisible ? 'pcl-badge-visible' : ''}`}
167→                        style={{ top: p.top, height: p.height }}
168→                        onMouseEnter={() => handleBadgeEnter(p.index)}
169→                        onMouseLeave={(event) => handleBadgeLeave(p.index, event)}
170→                    >
171→                        <button
172→                            className={`pcl-badge ${hasComments ? 'pcl-badge-active' : ''}`}
173→                            onClick={(e) => {
174→                                e.stopPropagation();
175→                                onParagraphClick({
176→                                    paragraphIndex: p.index,
177→                                    fingerprint: p.fingerprint,
178→                                    text: p.text,
179→                                });
180→                            }}
181→                        >
182→                            <CommentBadge count={count} hasComments={hasComments} />
183→                        </button>
184→                    </div>
185→                );
186→            })}
187→        </div>
188→    );
189→};
190→
191→export default ParagraphCommentLayer;
