 12→const CommentPanel = ({ chapterId, activeComment, onClose }) => {
 13→    const { user, session } = useAuth();
 14→    const token = session?.access_token;
 15→    const queryClient = useQueryClient();
 16→
 17→    const [body, setBody] = useState('');
 18→    const [replyTo, setReplyTo] = useState(null);
 19→    const [isMobile, setIsMobile] = useState(window.innerWidth <= 768);
 20→    const textareaRef = useRef(null);
 21→    const listRef = useRef(null);
 22→
 23→    const { paragraphIndex, fingerprint, text } = activeComment;
 24→
 25→    const { data: comments, isLoading } = useChapterComments(chapterId, paragraphIndex, token);
 26→    const addComment = useAddChapterComment(token);
 27→
 28→    useEffect(() => {
 29→        const handleResize = () => setIsMobile(window.innerWidth <= 768);
 30→        window.addEventListener('resize', handleResize);
 31→        return () => window.removeEventListener('resize', handleResize);
 32→    }, []);
 33→
 34→    useEffect(() => {
 35→        setReplyTo(null);
 36→        setBody('');
 37→    }, [paragraphIndex]);
 38→
 39→    const handleReply = (comment) => {
 40→        setReplyTo(comment);
 41→        textareaRef.current?.focus();
